// Package auth implements authentication and authorization for OwlDB.
package auth

import (
	"crypto/rand"
	"encoding/base64"
	"fmt"
	"strings"
	"sync"
	"time"
)

const tokenLength = 16
const tokenExpiry = time.Hour

// TokenInfo holds information about a bearer token.
type TokenInfo struct {
	Username  string
	ExpiresAt time.Time
}

// Manager manages authentication tokens.
type Manager struct {
	mu     sync.RWMutex
	tokens map[string]*TokenInfo
}

// NewManager creates a new token manager.
func NewManager() *Manager {
	return &Manager{
		tokens: make(map[string]*TokenInfo),
	}
}

// Login creates a new token for the given username.
// Returns the new token.
func (m *Manager) Login(username string) (string, error) {
	token, err := generateToken()
	if err != nil {
		return "", fmt.Errorf("failed to generate token: %w", err)
	}

	m.mu.Lock()
	m.tokens[token] = &TokenInfo{
		Username:  username,
		ExpiresAt: time.Now().Add(tokenExpiry),
	}
	m.mu.Unlock()

	return token, nil
}

// Logout invalidates the given token.
// Returns the username if the token was valid.
func (m *Manager) Logout(token string) (string, bool) {
	m.mu.Lock()
	defer m.mu.Unlock()

	info, exists := m.tokens[token]
	if !exists {
		return "", false
	}
	if time.Now().After(info.ExpiresAt) {
		delete(m.tokens, token)
		return "", false
	}

	username := info.Username
	delete(m.tokens, token)
	return username, true
}

// Validate checks if a bearer token is valid.
// Returns the username and true if valid, or empty string and false if not.
func (m *Manager) Validate(token string) (string, bool) {
	m.mu.RLock()
	info, exists := m.tokens[token]
	m.mu.RUnlock()

	if !exists {
		return "", false
	}
	if time.Now().After(info.ExpiresAt) {
		// Token expired; remove it
		m.mu.Lock()
		delete(m.tokens, token)
		m.mu.Unlock()
		return "", false
	}
	return info.Username, true
}

// AddToken adds a pre-existing token with a long expiry (from token file).
func (m *Manager) AddToken(token, username string, expiry time.Duration) {
	m.mu.Lock()
	m.tokens[token] = &TokenInfo{
		Username:  username,
		ExpiresAt: time.Now().Add(expiry),
	}
	m.mu.Unlock()
}

// ExtractBearerToken extracts the bearer token from an Authorization header value.
// Returns the token and true if successful.
func ExtractBearerToken(authHeader string) (string, bool) {
	const prefix = "Bearer "
	if !strings.HasPrefix(authHeader, prefix) {
		return "", false
	}
	token := strings.TrimSpace(authHeader[len(prefix):])
	if token == "" {
		return "", false
	}
	return token, true
}

// generateToken generates a cryptographically random token.
func generateToken() (string, error) {
	b := make([]byte, tokenLength)
	if _, err := rand.Read(b); err != nil {
		return "", err
	}
	// Use URL-safe base64 without padding
	token := base64.RawURLEncoding.EncodeToString(b)
	return token, nil
}

// Package db implements the in-memory document database for OwlDB.
// It uses a concurrent skip list as the underlying data structure for collections.
package db

import (
	"context"
	"encoding/json"
	"fmt"
	"strings"
	"sync"
	"time"

	"github.com/RICE-COMP318-FALL24/owldb-p1/jsondata"
	"github.com/RICE-COMP318-FALL24/owldb-p1/skiplist"
)

// Metadata holds the server-generated metadata for each document.
type Metadata struct {
	CreatedBy      string `json:"createdBy"`
	CreatedAt      int64  `json:"createdAt"`
	LastModifiedBy string `json:"lastModifiedBy"`
	LastModifiedAt int64  `json:"lastModifiedAt"`
}

// DocResponse is the response structure for a document retrieval.
type DocResponse struct {
	Path string             `json:"path"`
	Doc  jsondata.JSONValue `json:"doc"`
	Meta Metadata           `json:"meta"`
}

// PatchResult is the response structure for a patch operation.
type PatchResult struct {
	URI         string `json:"uri"`
	PatchFailed bool   `json:"patchFailed"`
	Message     string `json:"message"`
}

// EventType is the type of SSE event.
type EventType string

const (
	EventUpdate EventType = "update"
	EventDelete EventType = "delete"
)

// Event is an SSE event to be sent to subscribers.
type Event struct {
	Type EventType
	Path string
	Doc  *jsondata.JSONValue
	Meta *Metadata
}

// Document represents a single document stored in the database.
type Document struct {
	Body        jsondata.JSONValue
	Meta        Metadata
	Collections *skiplist.SkipList[string, *Collection]
	mu          sync.RWMutex
	docSubs     []chan Event
	dsMu        sync.Mutex
}

// RLock acquires a read lock on the document.
func (d *Document) RLock() { d.mu.RLock() }

// RUnlock releases a read lock on the document.
func (d *Document) RUnlock() { d.mu.RUnlock() }

// Collection represents a collection of documents stored in a skip list.
type Collection struct {
	Index   *skiplist.SkipList[string, *Document]
	colSubs []chan Event
	csMu    sync.Mutex
}

// AddSubscriber adds a subscriber channel to the collection.
func (c *Collection) AddSubscriber(ch chan Event) {
	c.csMu.Lock()
	c.colSubs = append(c.colSubs, ch)
	c.csMu.Unlock()
}

// RemoveSubscriber removes a subscriber and closes the channel.
func (c *Collection) RemoveSubscriber(ch chan Event) {
	c.csMu.Lock()
	for i, sub := range c.colSubs {
		if sub == ch {
			c.colSubs = append(c.colSubs[:i], c.colSubs[i+1:]...)
			break
		}
	}
	c.csMu.Unlock()
	// Drain and close
	for {
		select {
		case <-ch:
		default:
			close(ch)
			return
		}
	}
}

// NotifySubscribers sends an event to all collection subscribers.
func (c *Collection) NotifySubscribers(event Event) {
	c.csMu.Lock()
	subs := make([]chan Event, len(c.colSubs))
	copy(subs, c.colSubs)
	c.csMu.Unlock()
	for _, ch := range subs {
		select {
		case ch <- event:
		default:
		}
	}
}

// Database represents a single top-level database.
type Database struct {
	TopLevel *Collection
}

// Store is the top-level in-memory store containing all databases.
type Store struct {
	databases *skiplist.SkipList[string, *Database]
}

// NewStore creates a new empty store.
func NewStore() *Store {
	return &Store{
		databases: skiplist.New[string, *Database](),
	}
}

func newCollection() *Collection {
	return &Collection{
		Index: skiplist.New[string, *Document](),
	}
}

func newDatabase() *Database {
	return &Database{TopLevel: newCollection()}
}

// ConflictError is returned when nooverwrite mode finds an existing document.
type ConflictError struct{ Message string }

func (e *ConflictError) Error() string { return e.Message }

// --- Database management ---

func (s *Store) CreateDatabase(name string) error {
	_, err := s.databases.Upsert(name, func(key string, curr *Database, exists bool) (*Database, error) {
		if exists {
			return nil, fmt.Errorf("database already exists")
		}
		return newDatabase(), nil
	})
	return err
}

func (s *Store) DeleteDatabase(name string) (*Database, bool) {
	return s.databases.Remove(name)
}

func (s *Store) FindDatabase(name string) (*Database, bool) {
	return s.databases.Find(name)
}

// --- Path navigation ---

// navigateToCollection navigates the path to a collection.
// pathParts must have even length (or be empty for the top-level collection).
// Each pair of elements is (docName, colName).
func navigateToCollection(topLevel *Collection, pathParts []string) (*Collection, error) {
	if len(pathParts) == 0 {
		return topLevel, nil
	}
	if len(pathParts)%2 != 0 {
		return nil, fmt.Errorf("collection does not exist")
	}
	col := topLevel
	for i := 0; i < len(pathParts); i += 2 {
		docName := pathParts[i]
		colName := pathParts[i+1]
		doc, found := col.Index.Find(docName)
		if !found {
			return nil, fmt.Errorf("document does not exist")
		}
		subCol, found := doc.Collections.Find(colName)
		if !found {
			return nil, fmt.Errorf("collection does not exist")
		}
		col = subCol
	}
	return col, nil
}

// navigateToParentCollection returns the collection that directly contains pathParts[-1].
// pathParts must have odd length >= 1.
func navigateToParentCollection(topLevel *Collection, pathParts []string) (*Collection, error) {
	if len(pathParts) == 0 {
		return nil, fmt.Errorf("invalid path")
	}
	if len(pathParts) == 1 {
		return topLevel, nil
	}
	// Navigate via pairs: pathParts[0..n-2] interpreted as doc/col/doc/col/.../parentDoc/parentCol
	// Wait: for a document path like ["doc1","col1","doc2"], the parent collection is col1 which is
	// navigated by doc1→col1. So parent nav pairs: pathParts[0..len-2].
	// But len-2 elements must be even (to form doc/col pairs).
	parentParts := pathParts[:len(pathParts)-1]
	if len(parentParts)%2 != 0 {
		return nil, fmt.Errorf("collection does not exist")
	}
	return navigateToCollection(topLevel, parentParts)
}

// --- Collection operations ---

func (s *Store) CreateCollection(dbName string, pathParts []string) error {
	// pathParts must have even length >= 2 (last element is new collection name, second-to-last is parent doc)
	if len(pathParts) < 2 || len(pathParts)%2 != 0 {
		return fmt.Errorf("invalid collection path")
	}

	db, found := s.databases.Find(dbName)
	if !found {
		return fmt.Errorf("database does not exist")
	}

	// Navigate to parent document: pathParts[0..len-3] are doc/col pairs, pathParts[len-2] is parent doc
	parentColParts := pathParts[:len(pathParts)-2]
	parentColName := pathParts[len(pathParts)-2]
	newColName := pathParts[len(pathParts)-1]

	// Navigate to the collection containing the parent document
	col, err := navigateToCollection(db.TopLevel, parentColParts)
	if err != nil {
		return err
	}

	// Find parent document
	parentDoc, found := col.Index.Find(parentColName)
	if !found {
		return fmt.Errorf("document does not exist")
	}

	_, err = parentDoc.Collections.Upsert(newColName, func(key string, curr *Collection, exists bool) (*Collection, error) {
		if exists {
			return nil, fmt.Errorf("collection already exists")
		}
		return newCollection(), nil
	})
	return err
}

func (s *Store) DeleteCollection(dbName string, pathParts []string) (*Collection, bool, error) {
	if len(pathParts) < 2 || len(pathParts)%2 != 0 {
		return nil, false, fmt.Errorf("collection does not exist")
	}

	db, found := s.databases.Find(dbName)
	if !found {
		return nil, false, fmt.Errorf("database does not exist")
	}

	parentColParts := pathParts[:len(pathParts)-2]
	parentDocName := pathParts[len(pathParts)-2]
	colToDelete := pathParts[len(pathParts)-1]

	col, err := navigateToCollection(db.TopLevel, parentColParts)
	if err != nil {
		return nil, false, err
	}

	parentDoc, found := col.Index.Find(parentDocName)
	if !found {
		return nil, false, fmt.Errorf("document does not exist")
	}

	removedCol, removed := parentDoc.Collections.Remove(colToDelete)
	if !removed {
		return nil, false, fmt.Errorf("collection does not exist")
	}
	return removedCol, true, nil
}

// --- Document operations ---

func (s *Store) GetDocument(dbName string, pathParts []string) (*Document, error) {
	if len(pathParts) == 0 {
		return nil, fmt.Errorf("document does not exist")
	}
	db, found := s.databases.Find(dbName)
	if !found {
		return nil, fmt.Errorf("database does not exist")
	}
	col, err := navigateToParentCollection(db.TopLevel, pathParts)
	if err != nil {
		return nil, fmt.Errorf("document does not exist")
	}
	docName := pathParts[len(pathParts)-1]
	doc, found := col.Index.Find(docName)
	if !found {
		return nil, fmt.Errorf("document does not exist")
	}
	return doc, nil
}

// PutDocument creates or updates a document.
// Returns (wasUpdated, nil) on success or (false, error) on failure.
func (s *Store) PutDocument(dbName string, pathParts []string, body jsondata.JSONValue, username, mode string) (bool, error) {
	if len(pathParts) == 0 {
		return false, fmt.Errorf("invalid document path")
	}
	db, found := s.databases.Find(dbName)
	if !found {
		return false, fmt.Errorf("database does not exist")
	}
	col, err := navigateToParentCollection(db.TopLevel, pathParts)
	if err != nil {
		return false, err
	}
	docName := pathParts[len(pathParts)-1]
	now := time.Now().UnixMilli()
	var wasUpdated bool

	updated, upsertErr := col.Index.Upsert(docName, func(key string, curr *Document, exists bool) (*Document, error) {
		if exists {
			if mode == "nooverwrite" {
				return nil, &ConflictError{Message: "document already exists"}
			}
			curr.mu.Lock()
			curr.Body = body
			curr.Meta.LastModifiedBy = username
			curr.Meta.LastModifiedAt = now
			curr.mu.Unlock()
			wasUpdated = true
			return curr, nil
		}
		wasUpdated = false
		return &Document{
			Body: body,
			Meta: Metadata{
				CreatedBy:      username,
				CreatedAt:      now,
				LastModifiedBy: username,
				LastModifiedAt: now,
			},
			Collections: skiplist.New[string, *Collection](),
		}, nil
	})
	if upsertErr != nil {
		return false, upsertErr
	}
	_ = updated

	// Notify subscribers
	if doc, ok := col.Index.Find(docName); ok {
		fullPath := buildDocPath(dbName, pathParts)
		doc.mu.RLock()
		b := doc.Body
		m := doc.Meta
		doc.mu.RUnlock()
		ev := Event{Type: EventUpdate, Path: fullPath, Doc: &b, Meta: &m}
		notifyDocSubs(doc, ev)
		col.NotifySubscribers(ev)
	}
	return wasUpdated, nil
}

// PostDocument creates a document with a generated name and returns the name.
func (s *Store) PostDocument(dbName string, pathParts []string, body jsondata.JSONValue, username string) (string, error) {
	db, found := s.databases.Find(dbName)
	if !found {
		return "", fmt.Errorf("database does not exist")
	}
	var col *Collection
	if len(pathParts) == 0 {
		col = db.TopLevel
	} else {
		var err error
		col, err = navigateToCollection(db.TopLevel, pathParts)
		if err != nil {
			return "", err
		}
	}

	now := time.Now().UnixMilli()
	docName := generateID()
	doc := &Document{
		Body: body,
		Meta: Metadata{
			CreatedBy:      username,
			CreatedAt:      now,
			LastModifiedBy: username,
			LastModifiedAt: now,
		},
		Collections: skiplist.New[string, *Collection](),
	}

	_, err := col.Index.Upsert(docName, func(key string, curr *Document, exists bool) (*Document, error) {
		if exists {
			return nil, fmt.Errorf("generated name collision")
		}
		return doc, nil
	})
	if err != nil {
		return "", err
	}

	// Notify subscribers
	allParts := append(pathParts, docName)
	fullPath := buildDocPath(dbName, allParts)
	ev := Event{Type: EventUpdate, Path: fullPath, Doc: &body, Meta: &doc.Meta}
	col.NotifySubscribers(ev)

	return docName, nil
}

// DeleteDocument removes a document and returns it.
func (s *Store) DeleteDocument(dbName string, pathParts []string) (*Document, error) {
	if len(pathParts) == 0 {
		return nil, fmt.Errorf("document does not exist")
	}
	db, found := s.databases.Find(dbName)
	if !found {
		return nil, fmt.Errorf("database does not exist")
	}
	col, err := navigateToParentCollection(db.TopLevel, pathParts)
	if err != nil {
		return nil, fmt.Errorf("document does not exist")
	}
	docName := pathParts[len(pathParts)-1]
	removedDoc, removed := col.Index.Remove(docName)
	if !removed {
		return nil, fmt.Errorf("document does not exist")
	}

	// Notify subscribers
	fullPath := buildDocPath(dbName, pathParts)
	ev := Event{Type: EventDelete, Path: fullPath}
	notifyDocSubs(removedDoc, ev)
	col.NotifySubscribers(ev)

	return removedDoc, nil
}

// QueryCollection returns documents in a collection within [start, end].
func (s *Store) QueryCollection(dbName string, pathParts []string, start, end string) ([]DocResponse, error) {
	db, found := s.databases.Find(dbName)
	if !found {
		return nil, fmt.Errorf("database does not exist")
	}
	var col *Collection
	if len(pathParts) == 0 {
		col = db.TopLevel
	} else {
		var err error
		col, err = navigateToCollection(db.TopLevel, pathParts)
		if err != nil {
			return nil, err
		}
	}

	pairs, err := col.Index.Query(context.Background(), start, end)
	if err != nil {
		return nil, err
	}

	results := make([]DocResponse, 0, len(pairs))
	for _, pair := range pairs {
		doc := pair.Value
		doc.mu.RLock()
		var docPath string
		if len(pathParts) == 0 {
			docPath = "/v1/" + dbName + "/" + pair.Key
		} else {
			docPath = "/v1/" + dbName + "/" + strings.Join(pathParts, "/") + "/" + pair.Key
		}
		results = append(results, DocResponse{
			Path: docPath,
			Doc:  doc.Body,
			Meta: doc.Meta,
		})
		doc.mu.RUnlock()
	}
	return results, nil
}

// GetCollectionWithDocs returns the collection and initial query results.
func (s *Store) GetCollectionWithDocs(dbName string, pathParts []string, start, end string) (*Collection, []DocResponse, error) {
	db, found := s.databases.Find(dbName)
	if !found {
		return nil, nil, fmt.Errorf("database does not exist")
	}
	var col *Collection
	if len(pathParts) == 0 {
		col = db.TopLevel
	} else {
		var err error
		col, err = navigateToCollection(db.TopLevel, pathParts)
		if err != nil {
			return nil, nil, err
		}
	}

	docs, err := s.QueryCollection(dbName, pathParts, start, end)
	if err != nil {
		return nil, nil, err
	}
	return col, docs, nil
}

// --- Subscription ---

// SubscribeDocument returns a channel for document events.
func (s *Store) SubscribeDocument(dbName string, pathParts []string) (<-chan Event, func(), error) {
	doc, err := s.GetDocument(dbName, pathParts)
	if err != nil {
		return nil, nil, err
	}
	ch := make(chan Event, 100)
	doc.dsMu.Lock()
	doc.docSubs = append(doc.docSubs, ch)
	doc.dsMu.Unlock()

	unsub := func() {
		doc.dsMu.Lock()
		for i, sub := range doc.docSubs {
			if sub == ch {
				doc.docSubs = append(doc.docSubs[:i], doc.docSubs[i+1:]...)
				break
			}
		}
		doc.dsMu.Unlock()
		for {
			select {
			case <-ch:
			default:
				close(ch)
				return
			}
		}
	}
	return ch, unsub, nil
}

// --- PATCH ---

// PatchOperation represents a single patch operation.
type PatchOperation struct {
	Op    string             `json:"op"`
	Path  string             `json:"path"`
	Value jsondata.JSONValue `json:"value"`
}

// PatchDocument applies patches atomically to a document.
func (s *Store) PatchDocument(dbName string, pathParts []string, patches []PatchOperation, username string) (*PatchResult, error) {
	if len(pathParts) == 0 {
		return nil, fmt.Errorf("document does not exist")
	}
	db, found := s.databases.Find(dbName)
	if !found {
		return nil, fmt.Errorf("database does not exist")
	}
	col, err := navigateToParentCollection(db.TopLevel, pathParts)
	if err != nil {
		return nil, fmt.Errorf("document does not exist")
	}
	docName := pathParts[len(pathParts)-1]
	fullPath := buildDocPath(dbName, pathParts)
	result := &PatchResult{URI: fullPath}
	var notifyDoc *Document

	_, upsertErr := col.Index.Upsert(docName, func(key string, curr *Document, exists bool) (*Document, error) {
		if !exists {
			return nil, fmt.Errorf("document does not exist")
		}
		curr.mu.Lock()
		defer curr.mu.Unlock()

		newBody, err := applyPatches(curr.Body, patches)
		if err != nil {
			result.PatchFailed = true
			result.Message = err.Error()
			return curr, nil
		}
		now := time.Now().UnixMilli()
		curr.Body = newBody
		curr.Meta.LastModifiedBy = username
		curr.Meta.LastModifiedAt = now
		result.PatchFailed = false
		result.Message = "patch applied"
		notifyDoc = curr
		return curr, nil
	})
	if upsertErr != nil {
		return nil, upsertErr
	}

	if !result.PatchFailed && notifyDoc != nil {
		notifyDoc.mu.RLock()
		b := notifyDoc.Body
		m := notifyDoc.Meta
		notifyDoc.mu.RUnlock()
		ev := Event{Type: EventUpdate, Path: fullPath, Doc: &b, Meta: &m}
		notifyDocSubs(notifyDoc, ev)
		col.NotifySubscribers(ev)
	}

	return result, nil
}

// --- Helpers ---

func notifyDocSubs(doc *Document, event Event) {
	doc.dsMu.Lock()
	subs := make([]chan Event, len(doc.docSubs))
	copy(subs, doc.docSubs)
	doc.dsMu.Unlock()
	for _, ch := range subs {
		select {
		case ch <- event:
		default:
		}
	}
}

func buildDocPath(dbName string, pathParts []string) string {
	return "/v1/" + dbName + "/" + strings.Join(pathParts, "/")
}

func generateID() string {
	const chars = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789"
	b := make([]byte, 14)
	for i := range b {
		b[i] = chars[randIntn(len(chars))]
	}
	return string(b)
}

var (
	randMu    sync.Mutex
	randState uint64 = 0x12345678ABCDEF01
)

func randIntn(n int) int {
	randMu.Lock()
	x := randState
	x ^= x << 13
	x ^= x >> 7
	x ^= x << 17
	randState = x
	randMu.Unlock()
	return int(x%uint64(n))
}

// --- JSON Patch Implementation ---

func parsePointer(ptr string) ([]string, error) {
	if ptr == "" {
		return nil, nil
	}
	if !strings.HasPrefix(ptr, "/") {
		return nil, fmt.Errorf("invalid JSON pointer: must start with /")
	}
	parts := strings.Split(ptr[1:], "/")
	for i, p := range parts {
		p = strings.ReplaceAll(p, "~1", "/")
		p = strings.ReplaceAll(p, "~0", "~")
		parts[i] = p
	}
	return parts, nil
}

func applyPatches(body jsondata.JSONValue, patches []PatchOperation) (jsondata.JSONValue, error) {
	current := body
	for _, patch := range patches {
		segments, err := parsePointer(patch.Path)
		if err != nil {
			return body, fmt.Errorf("invalid path %q: %w", patch.Path, err)
		}
		newBody, err := applyOnePatch(current, segments, patch.Op, patch.Value)
		if err != nil {
			return body, err
		}
		current = newBody
	}
	return current, nil
}

func applyOnePatch(body jsondata.JSONValue, segments []string, op string, value jsondata.JSONValue) (jsondata.JSONValue, error) {
	visitor := &patchVisitor{segments: segments, op: op, value: value}
	return jsondata.Accept(body, visitor)
}

type patchVisitor struct {
	segments []string
	op       string
	value    jsondata.JSONValue
}

func (v *patchVisitor) Map(m map[string]jsondata.JSONValue) (jsondata.JSONValue, error) {
	if len(v.segments) == 0 {
		return jsondata.JSONValue{}, fmt.Errorf("path points to object, expected array or inner element")
	}

	key := v.segments[0]
	remaining := v.segments[1:]

	if len(remaining) == 0 {
		// Last segment
		switch v.op {
		case "ArrayAdd", "ArrayRemove":
			// key in this map should be an array
			arrVal, exists := m[key]
			if !exists {
				return jsondata.JSONValue{}, fmt.Errorf("path element %q not found", key)
			}
			newArr, err := applyArrayOp(arrVal, v.value, v.op == "ArrayAdd")
			if err != nil {
				return jsondata.JSONValue{}, err
			}
			newMap := copyMap(m)
			newMap[key] = newArr
			return jsondata.NewJSONValue(newMap)

		case "ObjectAdd":
			// key is the property to add to the current map (m)
			if _, exists := m[key]; exists {
				return jsondata.JSONValue{}, fmt.Errorf("property %q already exists", key)
			}
			newMap := copyMap(m)
			newMap[key] = v.value
			return jsondata.NewJSONValue(newMap)
		}
		return jsondata.JSONValue{}, fmt.Errorf("unknown op: %s", v.op)
	}

	// Navigate deeper
	child, exists := m[key]
	if !exists {
		return jsondata.JSONValue{}, fmt.Errorf("path element %q not found", key)
	}
	newChild, err := jsondata.Accept(child, &patchVisitor{segments: remaining, op: v.op, value: v.value})
	if err != nil {
		return jsondata.JSONValue{}, err
	}
	newMap := copyMap(m)
	newMap[key] = newChild
	return jsondata.NewJSONValue(newMap)
}

func (v *patchVisitor) Slice(s []jsondata.JSONValue) (jsondata.JSONValue, error) {
	if len(v.segments) == 0 {
		// We're at the target array - only valid for ArrayAdd/ArrayRemove with empty path
		switch v.op {
		case "ArrayAdd", "ArrayRemove":
			return applyArrayOp(jsonValueFromSlice(s), v.value, v.op == "ArrayAdd")
		}
		return jsondata.JSONValue{}, fmt.Errorf("cannot apply %s to array root", v.op)
	}
	return jsondata.JSONValue{}, fmt.Errorf("cannot navigate into array with key %q", v.segments[0])
}

func (v *patchVisitor) Bool(bool) (jsondata.JSONValue, error) {
	return jsondata.JSONValue{}, fmt.Errorf("cannot navigate into bool")
}
func (v *patchVisitor) Float64(float64) (jsondata.JSONValue, error) {
	return jsondata.JSONValue{}, fmt.Errorf("cannot navigate into number")
}
func (v *patchVisitor) String(string) (jsondata.JSONValue, error) {
	return jsondata.JSONValue{}, fmt.Errorf("cannot navigate into string")
}
func (v *patchVisitor) Null() (jsondata.JSONValue, error) {
	return jsondata.JSONValue{}, fmt.Errorf("cannot navigate into null")
}

// arrayOpVisitor applies ArrayAdd or ArrayRemove to an array.
type arrayOpVisitor struct {
	value jsondata.JSONValue
	add   bool
}

func (v *arrayOpVisitor) Slice(s []jsondata.JSONValue) (jsondata.JSONValue, error) {
	if v.add {
		for _, elem := range s {
			if elem.Equal(v.value) {
				return jsonValueFromSlice(s), nil
			}
		}
		newSlice := make([]jsondata.JSONValue, len(s)+1)
		copy(newSlice, s)
		newSlice[len(s)] = v.value
		return jsondata.NewJSONValue(newSlice)
	}
	newSlice := make([]jsondata.JSONValue, 0, len(s))
	for _, elem := range s {
		if !elem.Equal(v.value) {
			newSlice = append(newSlice, elem)
		}
	}
	return jsondata.NewJSONValue(newSlice)
}

func (v *arrayOpVisitor) Map(map[string]jsondata.JSONValue) (jsondata.JSONValue, error) {
	return jsondata.JSONValue{}, fmt.Errorf("expected array, got object")
}
func (v *arrayOpVisitor) Bool(bool) (jsondata.JSONValue, error) {
	return jsondata.JSONValue{}, fmt.Errorf("expected array, got bool")
}
func (v *arrayOpVisitor) Float64(float64) (jsondata.JSONValue, error) {
	return jsondata.JSONValue{}, fmt.Errorf("expected array, got number")
}
func (v *arrayOpVisitor) String(string) (jsondata.JSONValue, error) {
	return jsondata.JSONValue{}, fmt.Errorf("expected array, got string")
}
func (v *arrayOpVisitor) Null() (jsondata.JSONValue, error) {
	return jsondata.JSONValue{}, fmt.Errorf("expected array, got null")
}

func applyArrayOp(arr jsondata.JSONValue, value jsondata.JSONValue, add bool) (jsondata.JSONValue, error) {
	return jsondata.Accept(arr, &arrayOpVisitor{value: value, add: add})
}

func copyMap(m map[string]jsondata.JSONValue) map[string]jsondata.JSONValue {
	newMap := make(map[string]jsondata.JSONValue, len(m))
	for k, v := range m {
		newMap[k] = v
	}
	return newMap
}

func jsonValueFromSlice(s []jsondata.JSONValue) jsondata.JSONValue {
	v, _ := jsondata.NewJSONValue(s)
	return v
}

// LoadTokens parses a JSON object mapping usernames to tokens.
func LoadTokens(data []byte) (map[string]string, error) {
	var tokens map[string]string
	if err := json.Unmarshal(data, &tokens); err != nil {
		return nil, fmt.Errorf("invalid token file: %w", err)
	}
	return tokens, nil
}

// GetDocumentResponse builds a DocResponse for a document.
func GetDocumentResponse(path string, doc *Document) DocResponse {
	doc.mu.RLock()
	defer doc.mu.RUnlock()
	return DocResponse{Path: path, Doc: doc.Body, Meta: doc.Meta}
}

// Package handlers implements the HTTP request handlers for OwlDB.
package handlers

import (
	"encoding/json"
	"fmt"
	"io"
	"log/slog"
	"net/http"
	"strings"
	"time"

	"github.com/RICE-COMP318-FALL24/owldb-p1/auth"
	"github.com/RICE-COMP318-FALL24/owldb-p1/db"
	"github.com/RICE-COMP318-FALL24/owldb-p1/jsondata"
	"github.com/santhosh-tekuri/jsonschema/v5"
)

// Handler holds shared state for all HTTP handlers.
type Handler struct {
	store   *db.Store
	authMgr *auth.Manager
	schema  *jsonschema.Schema
}

// New creates a new Handler.
func New(store *db.Store, authMgr *auth.Manager, schema *jsonschema.Schema) *Handler {
	return &Handler{store: store, authMgr: authMgr, schema: schema}
}

// RegisterRoutes registers all routes on the given mux.
func (h *Handler) RegisterRoutes(mux *http.ServeMux) {
	mux.HandleFunc("/auth", h.handleAuth)
	mux.HandleFunc("/v1/", h.handleV1)
}

func setCORSHeaders(w http.ResponseWriter) {
	w.Header().Set("Access-Control-Allow-Origin", "*")
	w.Header().Set("Access-Control-Allow-Methods", "GET, PUT, POST, PATCH, DELETE, OPTIONS")
	w.Header().Set("Access-Control-Allow-Headers", "Authorization, Content-Type")
	w.Header().Set("Access-Control-Expose-Headers", "Location")
}

func writeJSON(w http.ResponseWriter, status int, v any) {
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(status)
	json.NewEncoder(w).Encode(v)
}

func writeError(w http.ResponseWriter, status int, msg string) {
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(status)
	json.NewEncoder(w).Encode(map[string]string{"error": msg})
}

func (h *Handler) validateAuth(w http.ResponseWriter, r *http.Request) (string, bool) {
	token, ok := auth.ExtractBearerToken(r.Header.Get("Authorization"))
	if !ok {
		writeError(w, http.StatusUnauthorized, "Missing or invalid bearer token")
		return "", false
	}
	username, ok := h.authMgr.Validate(token)
	if !ok {
		writeError(w, http.StatusUnauthorized, "Missing or invalid bearer token")
		return "", false
	}
	return username, true
}

// handleAuth handles POST /auth (login) and DELETE /auth (logout).
func (h *Handler) handleAuth(w http.ResponseWriter, r *http.Request) {
	setCORSHeaders(w)
	switch r.Method {
	case http.MethodOptions:
		w.Header().Set("Allow", "POST, DELETE, OPTIONS")
		w.WriteHeader(http.StatusNoContent)
	case http.MethodPost:
		h.handleLogin(w, r)
	case http.MethodDelete:
		h.handleLogout(w, r)
	default:
		writeError(w, http.StatusMethodNotAllowed, "Method not allowed")
	}
}

func (h *Handler) handleLogin(w http.ResponseWriter, r *http.Request) {
	body, err := io.ReadAll(r.Body)
	if err != nil {
		writeError(w, http.StatusBadRequest, "Failed to read request body")
		return
	}
	var req struct {
		Username string `json:"username"`
	}
	if err := json.Unmarshal(body, &req); err != nil || req.Username == "" {
		writeError(w, http.StatusBadRequest, "No username in request body")
		return
	}
	token, err := h.authMgr.Login(req.Username)
	if err != nil {
		writeError(w, http.StatusInternalServerError, "Failed to generate token")
		return
	}
	slog.Info("Login", "username", req.Username)
	writeJSON(w, http.StatusOK, map[string]string{"token": token})
}

func (h *Handler) handleLogout(w http.ResponseWriter, r *http.Request) {
	token, ok := auth.ExtractBearerToken(r.Header.Get("Authorization"))
	if !ok {
		writeError(w, http.StatusUnauthorized, "Missing or invalid bearer token")
		return
	}
	if _, ok := h.authMgr.Logout(token); !ok {
		writeError(w, http.StatusUnauthorized, "Missing or invalid bearer token")
		return
	}
	slog.Info("Logout")
	w.WriteHeader(http.StatusNoContent)
}

// handleV1 handles all /v1/... routes.
func (h *Handler) handleV1(w http.ResponseWriter, r *http.Request) {
	setCORSHeaders(w)
	if r.Method == http.MethodOptions {
		w.Header().Set("Allow", "GET, PUT, POST, PATCH, DELETE, OPTIONS")
		w.WriteHeader(http.StatusNoContent)
		return
	}

	path := r.URL.Path
	if !strings.HasPrefix(path, "/v1/") {
		writeError(w, http.StatusNotFound, "Not found")
		return
	}

	rest := path[len("/v1/"):]
	trailingSlash := strings.HasSuffix(rest, "/")
	if trailingSlash {
		rest = rest[:len(rest)-1]
	}

	var parts []string
	if rest != "" {
		parts = strings.Split(rest, "/")
	}

	if len(parts) == 0 {
		writeError(w, http.StatusBadRequest, "Missing database name")
		return
	}

	dbName := parts[0]
	resourceParts := parts[1:]

	slog.Debug("Request", "method", r.Method, "path", path, "db", dbName, "parts", resourceParts, "trailing", trailingSlash)

	if trailingSlash {
		if len(resourceParts) == 0 {
			h.handleDatabase(w, r, dbName)
		} else {
			h.handleCollection(w, r, dbName, resourceParts)
		}
	} else {
		if len(resourceParts) == 0 {
			// /v1/dbname (no trailing slash) - not a valid resource reference
			writeError(w, http.StatusBadRequest, "Database path must end with /")
			return
		}
		h.handleDocument(w, r, dbName, resourceParts)
	}
}

// handleDatabase handles /v1/{database}/ routes.
func (h *Handler) handleDatabase(w http.ResponseWriter, r *http.Request, dbName string) {
	switch r.Method {
	case http.MethodPut:
		username, ok := h.validateAuth(w, r)
		if !ok {
			return
		}
		_ = username
		if err := h.store.CreateDatabase(dbName); err != nil {
			if strings.Contains(err.Error(), "already exists") {
				writeError(w, http.StatusConflict, err.Error())
			} else {
				writeError(w, http.StatusBadRequest, err.Error())
			}
			return
		}
		loc := "/v1/" + dbName + "/"
		w.Header().Set("Location", loc)
		slog.Info("Database created", "name", dbName)
		writeJSON(w, http.StatusCreated, map[string]string{"uri": loc})

	case http.MethodDelete:
		if _, ok := h.validateAuth(w, r); !ok {
			return
		}
		deletedDB, removed := h.store.DeleteDatabase(dbName)
		if !removed {
			writeError(w, http.StatusNotFound, "Database does not exist")
			return
		}
		// Notify top-level collection subscribers about the deletion
		if deletedDB != nil {
			dbPath := "/v1/" + dbName + "/"
			deletedDB.TopLevel.NotifySubscribers(db.Event{Type: db.EventDelete, Path: dbPath})
		}
		slog.Info("Database deleted", "name", dbName)
		w.WriteHeader(http.StatusNoContent)

	case http.MethodGet:
		if _, ok := h.validateAuth(w, r); !ok {
			return
		}
		start, end, err := parseInterval(r.URL.Query().Get("interval"))
		if err != nil {
			writeError(w, http.StatusBadRequest, err.Error())
			return
		}
		if r.URL.Query().Get("mode") == "subscribe" {
			h.handleCollectionSubscribe(w, r, dbName, []string{}, start, end)
			return
		}
		docs, err := h.store.QueryCollection(dbName, []string{}, start, end)
		if err != nil {
			writeError(w, notFoundOrBadRequest(err), err.Error())
			return
		}
		writeJSON(w, http.StatusOK, docs)

	case http.MethodPost:
		username, ok := h.validateAuth(w, r)
		if !ok {
			return
		}
		h.doPostDocument(w, r, dbName, []string{}, username)

	default:
		writeError(w, http.StatusMethodNotAllowed, "Method not allowed")
	}
}

// handleCollection handles /v1/{database}/{collectionPath}/ routes.
func (h *Handler) handleCollection(w http.ResponseWriter, r *http.Request, dbName string, pathParts []string) {
	switch r.Method {
	case http.MethodPut:
		if _, ok := h.validateAuth(w, r); !ok {
			return
		}
		if err := h.store.CreateCollection(dbName, pathParts); err != nil {
			if strings.Contains(err.Error(), "document does not exist") {
				writeError(w, http.StatusNotFound, "Document does not exist")
			} else {
				writeError(w, http.StatusBadRequest, err.Error())
			}
			return
		}
		loc := "/v1/" + dbName + "/" + strings.Join(pathParts, "/") + "/"
		w.Header().Set("Location", loc)
		slog.Info("Collection created", "path", loc)
		writeJSON(w, http.StatusCreated, map[string]string{"uri": loc})

	case http.MethodDelete:
		if _, ok := h.validateAuth(w, r); !ok {
			return
		}
		removedCol, _, err := h.store.DeleteCollection(dbName, pathParts)
		if err != nil {
			if strings.Contains(err.Error(), "does not exist") {
				writeError(w, http.StatusNotFound, err.Error())
			} else {
				writeError(w, http.StatusBadRequest, err.Error())
			}
			return
		}
		if removedCol != nil {
			colPath := "/v1/" + dbName + "/" + strings.Join(pathParts, "/") + "/"
			removedCol.NotifySubscribers(db.Event{Type: db.EventDelete, Path: colPath})
		}
		slog.Info("Collection deleted", "path", pathParts)
		w.WriteHeader(http.StatusNoContent)

	case http.MethodGet:
		if _, ok := h.validateAuth(w, r); !ok {
			return
		}
		start, end, err := parseInterval(r.URL.Query().Get("interval"))
		if err != nil {
			writeError(w, http.StatusBadRequest, err.Error())
			return
		}
		if r.URL.Query().Get("mode") == "subscribe" {
			h.handleCollectionSubscribe(w, r, dbName, pathParts, start, end)
			return
		}
		docs, err := h.store.QueryCollection(dbName, pathParts, start, end)
		if err != nil {
			if strings.Contains(err.Error(), "does not exist") {
				writeError(w, http.StatusNotFound, err.Error())
			} else {
				writeError(w, http.StatusBadRequest, err.Error())
			}
			return
		}
		writeJSON(w, http.StatusOK, docs)

	case http.MethodPost:
		username, ok := h.validateAuth(w, r)
		if !ok {
			return
		}
		h.doPostDocument(w, r, dbName, pathParts, username)

	default:
		writeError(w, http.StatusMethodNotAllowed, "Method not allowed")
	}
}

// handleDocument handles /v1/{database}/{documentPath} routes.
func (h *Handler) handleDocument(w http.ResponseWriter, r *http.Request, dbName string, pathParts []string) {
	switch r.Method {
	case http.MethodGet:
		if _, ok := h.validateAuth(w, r); !ok {
			return
		}
		if r.URL.Query().Get("mode") == "subscribe" {
			h.handleDocumentSubscribe(w, r, dbName, pathParts)
			return
		}
		doc, err := h.store.GetDocument(dbName, pathParts)
		if err != nil {
			writeError(w, notFoundOrBadRequest(err), err.Error())
			return
		}
		fullPath := "/v1/" + dbName + "/" + strings.Join(pathParts, "/")
		writeJSON(w, http.StatusOK, db.GetDocumentResponse(fullPath, doc))

	case http.MethodPut:
		username, ok := h.validateAuth(w, r)
		if !ok {
			return
		}
		h.doPutDocument(w, r, dbName, pathParts, username)

	case http.MethodPatch:
		username, ok := h.validateAuth(w, r)
		if !ok {
			return
		}
		h.doPatchDocument(w, r, dbName, pathParts, username)

	case http.MethodDelete:
		if _, ok := h.validateAuth(w, r); !ok {
			return
		}
		if _, err := h.store.DeleteDocument(dbName, pathParts); err != nil {
			writeError(w, notFoundOrBadRequest(err), err.Error())
			return
		}
		slog.Info("Document deleted", "path", pathParts)
		w.WriteHeader(http.StatusNoContent)

	default:
		writeError(w, http.StatusMethodNotAllowed, "Method not allowed")
	}
}

func (h *Handler) doPutDocument(w http.ResponseWriter, r *http.Request, dbName string, pathParts []string, username string) {
	body, err := io.ReadAll(r.Body)
	if err != nil {
		writeError(w, http.StatusBadRequest, "Failed to read request body")
		return
	}
	docVal, err := parseAndValidate(body, h.schema)
	if err != nil {
		writeError(w, http.StatusBadRequest, err.Error())
		return
	}
	mode := r.URL.Query().Get("mode")
	if mode == "" {
		mode = "overwrite"
	}
	wasUpdated, err := h.store.PutDocument(dbName, pathParts, docVal, username, mode)
	if err != nil {
		if _, ok := err.(*db.ConflictError); ok {
			writeError(w, http.StatusPreconditionFailed, err.Error())
			return
		}
		writeError(w, notFoundOrBadRequest(err), err.Error())
		return
	}
	fullPath := "/v1/" + dbName + "/" + strings.Join(pathParts, "/")
	w.Header().Set("Location", fullPath)
	if wasUpdated {
		writeJSON(w, http.StatusOK, map[string]string{"uri": fullPath})
	} else {
		writeJSON(w, http.StatusCreated, map[string]string{"uri": fullPath})
	}
}

func (h *Handler) doPostDocument(w http.ResponseWriter, r *http.Request, dbName string, pathParts []string, username string) {
	body, err := io.ReadAll(r.Body)
	if err != nil {
		writeError(w, http.StatusBadRequest, "Failed to read request body")
		return
	}
	docVal, err := parseAndValidate(body, h.schema)
	if err != nil {
		writeError(w, http.StatusBadRequest, err.Error())
		return
	}
	docName, err := h.store.PostDocument(dbName, pathParts, docVal, username)
	if err != nil {
		writeError(w, notFoundOrBadRequest(err), err.Error())
		return
	}
	var fullPath string
	if len(pathParts) == 0 {
		fullPath = "/v1/" + dbName + "/" + docName
	} else {
		fullPath = "/v1/" + dbName + "/" + strings.Join(pathParts, "/") + "/" + docName
	}
	w.Header().Set("Location", fullPath)
	slog.Info("Document posted", "path", fullPath)
	writeJSON(w, http.StatusCreated, map[string]string{"uri": fullPath})
}

func (h *Handler) doPatchDocument(w http.ResponseWriter, r *http.Request, dbName string, pathParts []string, username string) {
	body, err := io.ReadAll(r.Body)
	if err != nil {
		writeError(w, http.StatusBadRequest, "Failed to read request body")
		return
	}
	var patches []db.PatchOperation
	if err := json.Unmarshal(body, &patches); err != nil {
		writeError(w, http.StatusBadRequest, fmt.Sprintf("Invalid patch body: %s", err.Error()))
		return
	}
	result, err := h.store.PatchDocument(dbName, pathParts, patches, username)
	if err != nil {
		writeError(w, notFoundOrBadRequest(err), err.Error())
		return
	}
	fullPath := "/v1/" + dbName + "/" + strings.Join(pathParts, "/")
	w.Header().Set("Location", fullPath)
	writeJSON(w, http.StatusOK, result)
}

// handleDocumentSubscribe handles SSE subscription to a document.
func (h *Handler) handleDocumentSubscribe(w http.ResponseWriter, r *http.Request, dbName string, pathParts []string) {
	flusher, ok := w.(http.Flusher)
	if !ok {
		writeError(w, http.StatusInternalServerError, "Streaming not supported")
		return
	}

	doc, err := h.store.GetDocument(dbName, pathParts)
	if err != nil {
		writeError(w, notFoundOrBadRequest(err), err.Error())
		return
	}

	ch, unsub, err := h.store.SubscribeDocument(dbName, pathParts)
	if err != nil {
		writeError(w, http.StatusInternalServerError, err.Error())
		return
	}
	defer unsub()

	w.Header().Set("Content-Type", "text/event-stream")
	w.Header().Set("Cache-Control", "no-cache")
	w.Header().Set("Connection", "keep-alive")
	w.WriteHeader(http.StatusOK)

	// Send initial document state
	fullPath := "/v1/" + dbName + "/" + strings.Join(pathParts, "/")
	doc.RLock()
	body := doc.Body
	meta := doc.Meta
	doc.RUnlock()
	sendUpdateEvent(w, fullPath, &body, &meta)
	flusher.Flush()

	ticker := time.NewTicker(15 * time.Second)
	defer ticker.Stop()
	for {
		select {
		case event, ok := <-ch:
			if !ok {
				return
			}
			if event.Type == db.EventUpdate {
				sendUpdateEvent(w, event.Path, event.Doc, event.Meta)
			} else {
				sendDeleteEvent(w, event.Path)
			}
			flusher.Flush()
		case <-ticker.C:
			fmt.Fprintf(w, ": heartbeat\n\n")
			flusher.Flush()
		case <-r.Context().Done():
			return
		}
	}
}

// handleCollectionSubscribe handles SSE subscription to a collection.
func (h *Handler) handleCollectionSubscribe(w http.ResponseWriter, r *http.Request, dbName string, pathParts []string, start, end string) {
	flusher, ok := w.(http.Flusher)
	if !ok {
		writeError(w, http.StatusInternalServerError, "Streaming not supported")
		return
	}

	col, initialDocs, err := h.store.GetCollectionWithDocs(dbName, pathParts, start, end)
	if err != nil {
		writeError(w, notFoundOrBadRequest(err), err.Error())
		return
	}

	ch := make(chan db.Event, 100)
	col.AddSubscriber(ch)
	defer col.RemoveSubscriber(ch)

	w.Header().Set("Content-Type", "text/event-stream")
	w.Header().Set("Cache-Control", "no-cache")
	w.Header().Set("Connection", "keep-alive")
	w.WriteHeader(http.StatusOK)

	for _, doc := range initialDocs {
		sendUpdateEvent(w, doc.Path, &doc.Doc, &doc.Meta)
	}
	flusher.Flush()

	ticker := time.NewTicker(15 * time.Second)
	defer ticker.Stop()
	for {
		select {
		case event, ok := <-ch:
			if !ok {
				return
			}
			// Filter by interval (skip filter for collection-level delete events)
			isCollectionDelete := event.Type == db.EventDelete && strings.HasSuffix(event.Path, "/")
			if !isCollectionDelete && (start != "" || end != "") {
				docName := extractLastPathComponent(event.Path)
				if start != "" && docName < start {
					continue
				}
				if end != "" && docName > end {
					continue
				}
			}
			if event.Type == db.EventUpdate {
				sendUpdateEvent(w, event.Path, event.Doc, event.Meta)
			} else {
				sendDeleteEvent(w, event.Path)
			}
			flusher.Flush()
		case <-ticker.C:
			fmt.Fprintf(w, ": heartbeat\n\n")
			flusher.Flush()
		case <-r.Context().Done():
			return
		}
	}
}

func sendUpdateEvent(w http.ResponseWriter, path string, docBody *jsondata.JSONValue, meta *db.Metadata) {
	type updateData struct {
		Path string             `json:"path"`
		Doc  jsondata.JSONValue `json:"doc"`
		Meta db.Metadata        `json:"meta"`
	}
	data := updateData{Path: path, Doc: *docBody, Meta: *meta}
	dataBytes, err := json.Marshal(data)
	if err != nil {
		return
	}
	id := time.Now().UnixMilli()
	fmt.Fprintf(w, "event: update\ndata: %s\nid: %d\n\n", string(dataBytes), id)
}

func sendDeleteEvent(w http.ResponseWriter, path string) {
	pathBytes, _ := json.Marshal(path)
	id := time.Now().UnixMilli()
	fmt.Fprintf(w, "event: delete\ndata: %s\nid: %d\n\n", string(pathBytes), id)
}

func parseAndValidate(body []byte, schema *jsonschema.Schema) (jsondata.JSONValue, error) {
	var docVal jsondata.JSONValue
	if err := json.Unmarshal(body, &docVal); err != nil {
		return jsondata.JSONValue{}, fmt.Errorf("invalid JSON: %s", err.Error())
	}
	if schema != nil {
		if err := docVal.Validate(schema); err != nil {
			return jsondata.JSONValue{}, fmt.Errorf("document does not conform to schema: %s", err.Error())
		}
	}
	return docVal, nil
}

func parseInterval(interval string) (start, end string, err error) {
	if interval == "" {
		return "", "", nil
	}
	if !strings.HasPrefix(interval, "[") || !strings.HasSuffix(interval, "]") {
		return "", "", fmt.Errorf("invalid interval format: must be [low,high]")
	}
	inner := interval[1 : len(interval)-1]
	idx := strings.Index(inner, ",")
	if idx == -1 {
		return "", "", fmt.Errorf("invalid interval format: missing comma")
	}
	return strings.TrimSpace(inner[:idx]), strings.TrimSpace(inner[idx+1:]), nil
}

func extractLastPathComponent(path string) string {
	path = strings.TrimSuffix(path, "/")
	if idx := strings.LastIndex(path, "/"); idx >= 0 {
		return path[idx+1:]
	}
	return path
}

func notFoundOrBadRequest(err error) int {
	if strings.Contains(err.Error(), "does not exist") {
		return http.StatusNotFound
	}
	return http.StatusBadRequest
}

// OwlDB is an in-memory NoSQL document database with a RESTful HTTP API.
package main

import (
	"bytes"
	"flag"
	"fmt"
	"log/slog"
	"net/http"
	"os"
	"os/signal"
	"syscall"
	"time"

	"github.com/RICE-COMP318-FALL24/owldb-p1/auth"
	"github.com/RICE-COMP318-FALL24/owldb-p1/db"
	"github.com/RICE-COMP318-FALL24/owldb-p1/handlers"
	"github.com/santhosh-tekuri/jsonschema/v5"
)

func main() {
	var port int
	var schemaFile string
	var tokenFile string

	flag.IntVar(&port, "p", 3318, "Port to listen on")
	flag.StringVar(&schemaFile, "s", "", "Path to JSON schema file (required)")
	flag.StringVar(&tokenFile, "t", "", "Path to JSON token file")
	flag.Parse()

	if schemaFile == "" {
		fmt.Fprintln(os.Stderr, "Error: -s flag is required (JSON schema file)")
		os.Exit(1)
	}

	// Set up logging
	logOpts := &slog.HandlerOptions{Level: slog.LevelInfo}
	handler := slog.NewTextHandler(os.Stdout, logOpts)
	slog.SetDefault(slog.New(handler))

	// Load and compile JSON schema
	compiler := jsonschema.NewCompiler()
	schemaData, err := os.ReadFile(schemaFile)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: failed to read schema file %q: %v\n", schemaFile, err)
		os.Exit(1)
	}

	schemaURL := "file://document.json"
	if err := compiler.AddResource(schemaURL, bytes.NewReader(schemaData)); err != nil {
		fmt.Fprintf(os.Stderr, "Error: failed to add schema resource: %v\n", err)
		os.Exit(1)
	}

	schema, err := compiler.Compile(schemaURL)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: failed to compile schema: %v\n", err)
		os.Exit(1)
	}

	// Create store and auth manager
	store := db.NewStore()
	authMgr := auth.NewManager()

	// Load token file if provided
	if tokenFile != "" {
		tokenData, err := os.ReadFile(tokenFile)
		if err != nil {
			fmt.Fprintf(os.Stderr, "Error: failed to read token file %q: %v\n", tokenFile, err)
			os.Exit(1)
		}
		tokens, err := db.LoadTokens(tokenData)
		if err != nil {
			fmt.Fprintf(os.Stderr, "Error: failed to parse token file: %v\n", err)
			os.Exit(1)
		}
		// Add tokens with 24-hour+ expiry
		for username, token := range tokens {
			authMgr.AddToken(token, username, 48*time.Hour)
		}
		slog.Info("Loaded tokens", "count", len(tokens))
	}

	// Set up HTTP server
	mux := http.NewServeMux()
	h := handlers.New(store, authMgr, schema)
	h.RegisterRoutes(mux)

	var server http.Server
	server.Addr = fmt.Sprintf(":%d", port)
	server.Handler = mux

	// The following code should go last and remain unchanged.
	// Note that you must actually initialize 'server' and 'port'
	// before this.  Note that the server is started below by
	// calling ListenAndServe.  You must not start the server
	// before this.

	// signal.Notify requires the channel to be buffered
	ctrlc := make(chan os.Signal, 1)
	signal.Notify(ctrlc, os.Interrupt, syscall.SIGTERM)
	go func() {
		// Wait for Ctrl-C signal
		<-ctrlc
		server.Close()
	}()

	// Start server
	slog.Info("Listening", "port", port)
	err = server.ListenAndServe()
	if err != nil && err != http.ErrServerClosed {
		slog.Error("Server closed", "error", err)
	} else {
		slog.Info("Server closed", "error", err)
	}
}

// Package skiplist implements a concurrent skip list with lazy synchronization.
// Uses atomics for lock-free reads and fine-grained locking for writes.
package skiplist

import (
	"cmp"
	"context"
	"math/rand"
	"sync"
	"sync/atomic"
)

const maxLevel = 16
const probability = 0.25

// UpdateCheck is a function called atomically by Upsert.
// exists=true means key already exists with currValue.
// Return (newValue, nil) to perform the upsert, or (_, err) to abort.
type UpdateCheck[K cmp.Ordered, V any] func(key K, currValue V, exists bool) (newValue V, err error)

// Pair holds a key-value pair returned by Query.
type Pair[K cmp.Ordered, V any] struct {
	Key   K
	Value V
}

// DBIndex is the interface implemented by SkipList.
type DBIndex[K cmp.Ordered, V any] interface {
	Upsert(key K, check UpdateCheck[K, V]) (updated bool, err error)
	Remove(key K) (removedValue V, removed bool)
	Find(key K) (foundValue V, found bool)
	Query(ctx context.Context, start K, end K) (results []Pair[K, V], err error)
}

type node[K cmp.Ordered, V any] struct {
	key         K
	val         atomic.Pointer[V]
	topLevel    int
	next        [maxLevel]atomic.Pointer[node[K, V]]
	mu          sync.Mutex
	marked      atomic.Bool // logically deleted
	fullyLinked atomic.Bool // fully inserted at all levels
	isHead      bool
	isTail      bool
}

// SkipList is a concurrent lazy skip list.
type SkipList[K cmp.Ordered, V any] struct {
	head *node[K, V]
	tail *node[K, V]
}

// New creates a new empty SkipList.
func New[K cmp.Ordered, V any]() *SkipList[K, V] {
	head := &node[K, V]{topLevel: maxLevel - 1, isHead: true}
	tail := &node[K, V]{topLevel: maxLevel - 1, isTail: true}
	for i := 0; i < maxLevel; i++ {
		head.next[i].Store(tail)
	}
	head.fullyLinked.Store(true)
	tail.fullyLinked.Store(true)
	return &SkipList[K, V]{head: head, tail: tail}
}

// nodeKeyLT returns true if n's key is strictly less than key.
func (sl *SkipList[K, V]) nodeKeyLT(n *node[K, V], key K) bool {
	if n.isHead {
		return true
	}
	if n.isTail {
		return false
	}
	return cmp.Compare(n.key, key) < 0
}

// nodeKeyEQ returns true if n's key equals key.
func (sl *SkipList[K, V]) nodeKeyEQ(n *node[K, V], key K) bool {
	if n.isHead || n.isTail {
		return false
	}
	return cmp.Compare(n.key, key) == 0
}

// randomLevel returns a random level for a new node (1..maxLevel).
func randomLevel() int {
	level := 1
	for level < maxLevel && rand.Float64() < probability {
		level++
	}
	return level
}

type findResult[K cmp.Ordered, V any] struct {
	found bool
	preds [maxLevel]*node[K, V]
	succs [maxLevel]*node[K, V]
}

// find searches for key and returns predecessor/successor arrays.
// Retries until a stable view of the candidate node is obtained.
func (sl *SkipList[K, V]) find(key K) findResult[K, V] {
	for {
		var r findResult[K, V]
		lFound := -1
		pred := sl.head

		for level := maxLevel - 1; level >= 0; level-- {
			curr := pred.next[level].Load()
			for sl.nodeKeyLT(curr, key) {
				pred = curr
				curr = pred.next[level].Load()
			}
			if lFound == -1 && sl.nodeKeyEQ(curr, key) {
				lFound = level
			}
			r.preds[level] = pred
			r.succs[level] = curr
		}

		if lFound == -1 {
			return r // not found
		}
		candidate := r.succs[lFound]
		if candidate.fullyLinked.Load() && !candidate.marked.Load() {
			r.found = true
			return r
		}
		// Candidate is being inserted or removed; spin-wait for stability
		// (operations complete in O(1) time, so spinning is acceptable)
	}
}

// lockPreds locks predecessor nodes for levels 0..topLevel.
// Avoids double-locking: if pred[i] == pred[i-1], it's only locked once.
// Returns (lockedPreds, highestLocked, valid).
func (sl *SkipList[K, V]) lockPreds(r findResult[K, V], topLevel int) ([maxLevel]*node[K, V], int, bool) {
	var lockedPreds [maxLevel]*node[K, V]
	highestLocked := -1
	valid := true
	var prevPred *node[K, V]

	for level := 0; valid && level <= topLevel; level++ {
		pred := r.preds[level]
		succ := r.succs[level]

		if pred != prevPred {
			pred.mu.Lock()
			highestLocked = level
			prevPred = pred
		}
		lockedPreds[level] = pred

		if pred.marked.Load() || pred.next[level].Load() != succ {
			valid = false
		}
	}
	return lockedPreds, highestLocked, valid
}

// lockPredsForRemove locks preds verifying each points to nodeToDelete.
func (sl *SkipList[K, V]) lockPredsForRemove(r findResult[K, V], topLevel int, nodeToDelete *node[K, V]) ([maxLevel]*node[K, V], int, bool) {
	var lockedPreds [maxLevel]*node[K, V]
	highestLocked := -1
	valid := true
	var prevPred *node[K, V]

	for level := 0; valid && level <= topLevel; level++ {
		pred := r.preds[level]
		if pred != prevPred {
			pred.mu.Lock()
			highestLocked = level
			prevPred = pred
		}
		lockedPreds[level] = pred

		if pred.marked.Load() || pred.next[level].Load() != nodeToDelete {
			valid = false
		}
	}
	return lockedPreds, highestLocked, valid
}

// unlockPreds releases unique predecessor locks.
func unlockPreds[K cmp.Ordered, V any](lockedPreds [maxLevel]*node[K, V], highestLocked int) {
	var prevPred *node[K, V]
	for level := 0; level <= highestLocked; level++ {
		if lockedPreds[level] != prevPred {
			lockedPreds[level].mu.Unlock()
			prevPred = lockedPreds[level]
		}
	}
}

// Upsert inserts or updates key in the skip list.
// Returns (true, nil) if updated, (false, nil) if inserted, or (_, err) if aborted.
func (sl *SkipList[K, V]) Upsert(key K, check UpdateCheck[K, V]) (updated bool, err error) {
	topLevel := randomLevel() - 1

	for {
		r := sl.find(key)

		if r.found {
			// Update existing node under its lock
			nodeToUpdate := r.succs[0]
			nodeToUpdate.mu.Lock()
			if nodeToUpdate.marked.Load() {
				nodeToUpdate.mu.Unlock()
				continue // node was concurrently removed; retry
			}
			var currVal V
			if ptr := nodeToUpdate.val.Load(); ptr != nil {
				currVal = *ptr
			}
			newVal, checkErr := check(key, currVal, true)
			if checkErr != nil {
				nodeToUpdate.mu.Unlock()
				return true, checkErr
			}
			nodeToUpdate.val.Store(&newVal)
			nodeToUpdate.mu.Unlock()
			return true, nil
		}

		// Insert new node
		lockedPreds, highestLocked, valid := sl.lockPreds(r, topLevel)
		if !valid {
			unlockPreds[K, V](lockedPreds, highestLocked)
			continue // retry
		}

		var zero V
		newVal, checkErr := check(key, zero, false)
		if checkErr != nil {
			unlockPreds[K, V](lockedPreds, highestLocked)
			return false, checkErr
		}

		newNode := &node[K, V]{key: key, topLevel: topLevel}
		newNode.val.Store(&newVal)

		for level := 0; level <= topLevel; level++ {
			newNode.next[level].Store(r.succs[level])
			r.preds[level].next[level].Store(newNode)
		}
		newNode.fullyLinked.Store(true)

		unlockPreds[K, V](lockedPreds, highestLocked)
		return false, nil
	}
}

// Remove removes the node with the given key.
// Returns the removed value and true if found and removed.
func (sl *SkipList[K, V]) Remove(key K) (removedValue V, removed bool) {
	var nodeToDelete *node[K, V]
	isMarked := false
	topLevel := -1

	for {
		r := sl.find(key)

		if !isMarked {
			if !r.found {
				var zero V
				return zero, false
			}
			nodeToDelete = r.succs[0]
			topLevel = nodeToDelete.topLevel

			nodeToDelete.mu.Lock()
			if nodeToDelete.marked.Load() {
				nodeToDelete.mu.Unlock()
				var zero V
				return zero, false // already removed by another goroutine
			}
			if ptr := nodeToDelete.val.Load(); ptr != nil {
				removedValue = *ptr
			}
			nodeToDelete.marked.Store(true)
			isMarked = true
			nodeToDelete.mu.Unlock()
		}

		// Physically unlink the node
		lockedPreds, highestLocked, valid := sl.lockPredsForRemove(r, topLevel, nodeToDelete)
		if !valid {
			unlockPreds[K, V](lockedPreds, highestLocked)
			// Refresh preds and retry physical unlink
			r = sl.findForRemove(key, nodeToDelete, topLevel)
			lockedPreds, highestLocked, valid = sl.lockPredsForRemove(r, topLevel, nodeToDelete)
			if !valid {
				unlockPreds[K, V](lockedPreds, highestLocked)
				continue
			}
		}

		for level := topLevel; level >= 0; level-- {
			r.preds[level].next[level].Store(nodeToDelete.next[level].Load())
		}
		unlockPreds[K, V](lockedPreds, highestLocked)
		return removedValue, true
	}
}

// findForRemove finds predecessors of the given node at each level.
func (sl *SkipList[K, V]) findForRemove(key K, target *node[K, V], topLevel int) findResult[K, V] {
	var r findResult[K, V]
	pred := sl.head
	for level := maxLevel - 1; level >= 0; level-- {
		curr := pred.next[level].Load()
		for curr != target && sl.nodeKeyLT(curr, key) {
			pred = curr
			curr = pred.next[level].Load()
		}
		r.preds[level] = pred
		r.succs[level] = curr
	}
	return r
}

// Find looks up a key without modifying the list.
func (sl *SkipList[K, V]) Find(key K) (foundValue V, found bool) {
	pred := sl.head
	for level := maxLevel - 1; level >= 0; level-- {
		curr := pred.next[level].Load()
		for sl.nodeKeyLT(curr, key) {
			pred = curr
			curr = pred.next[level].Load()
		}
		if sl.nodeKeyEQ(curr, key) {
			if curr.fullyLinked.Load() && !curr.marked.Load() {
				if ptr := curr.val.Load(); ptr != nil {
					return *ptr, true
				}
			}
			break
		}
	}
	var zero V
	return zero, false
}

// Query returns all key-value pairs with keys in [start, end].
// Empty string (zero value) for start/end means unbounded.
func (sl *SkipList[K, V]) Query(ctx context.Context, start K, end K) ([]Pair[K, V], error) {
	var zero K
	hasStart := cmp.Compare(start, zero) != 0
	hasEnd := cmp.Compare(end, zero) != 0

	var results []Pair[K, V]
	curr := sl.head.next[0].Load()
	for curr != sl.tail {
		if err := ctx.Err(); err != nil {
			return nil, err
		}
		if !curr.marked.Load() && curr.fullyLinked.Load() {
			if hasStart && cmp.Compare(curr.key, start) < 0 {
				curr = curr.next[0].Load()
				continue
			}
			if hasEnd && cmp.Compare(curr.key, end) > 0 {
				break
			}
			if ptr := curr.val.Load(); ptr != nil {
				results = append(results, Pair[K, V]{Key: curr.key, Value: *ptr})
			}
		}
		curr = curr.next[0].Load()
	}
	return results, nil
}

// ForEach calls f for each element in order. Stops if f returns false.
func (sl *SkipList[K, V]) ForEach(f func(key K, value V) bool) {
	curr := sl.head.next[0].Load()
	for curr != sl.tail {
		if !curr.marked.Load() && curr.fullyLinked.Load() {
			if ptr := curr.val.Load(); ptr != nil {
				if !f(curr.key, *ptr) {
					return
				}
			}
		}
		curr = curr.next[0].Load()
	}
}

// Ensure SkipList implements DBIndex.
var _ DBIndex[string, any] = (*SkipList[string, any])(nil)

